#include <bits/stdc++.h>
using namespace std;
set<int> c;
int main(){
    int n,a[1003];
    cin>>n;
    c.clear();
    for(int i=1;i<=n;i++){
        cin>>a[i];
        //cout<<abs(a[i]-a[i-1])<<endl;
        if(i>1 && (abs(a[i]-a[i-1])<1 || abs(a[i]-a[i-1])>=n)){
            cout<<"Not jolly";
            return 0;
        }
        if(i>1)c.insert(abs(a[i]-a[i-1]));
    }
    //cout<<c.size(); 
    if(c.size()==n-1)cout<<"Jolly";
    else cout<<"Not jolly";
    return 0;
}
